- "specific dataset" refers to the dataset with dataset_id = 1001; 
- "highly zoomed" implies a zoom level greater than 15 in the context of the tiles;
- "detailed tiles" relates to the tiles associated with the given dataset_id and meeting the zoom level criteria.

sql:
SELECT dataset_id, COUNT(report_id) AS total_reports 
FROM analysis_reports 
GROUP BY dataset_id;

SELECT COUNT(dataset_id) AS total_datasets, upload_date 
FROM geospatial_data
GROUP BY upload_date;

SELECT dataset_id, COUNT(DISTINCT data_source) AS distinct_data_sources_count 
FROM geospatial_data 
GROUP BY dataset_id;

SELECT geospatial_data.data_source, COUNT(geospatial_data.dataset_id) AS dataset_count
FROM geospatial_data
GROUP BY geospatial_data.data_source;

SELECT DISTINCT dataset_id, attribute_name
FROM attributes
WHERE attribute_value LIKE '%Your_Search_Term%';

SELECT dataset_id, attributes
FROM geospatial_data
WHERE attributes < (SELECT AVG(attributes) FROM geospatial_data);

SELECT dataset_id, attributes
FROM geospatial_data
WHERE attributes = (
    SELECT MAX(attributes)
    FROM geospatial_data
);
